use alloy::primitives::{keccak256, Address, B256, U256};
use std::sync::LazyLock;
use tracing::{info, warn};

/// Cached init code hash for V1 — computed once, reused for every predict_token_address call.
static CACHED_INIT_CODE_HASH_V1: LazyLock<B256> = LazyLock::new(compute_init_code_hash);

/// Cached init code hash for V2 — computed once.
static CACHED_INIT_CODE_HASH_V2: LazyLock<B256> = LazyLock::new(compute_init_code_hash_v2);

/// Init code hash for four.meme token contract V1 (constant for all tokens)
pub const TOKEN_INIT_CODE_HASH: [u8; 32] = [0u8; 32];

/// Compute keccak256 hash of the token init code
pub fn compute_init_code_hash() -> B256 {
    // Token init code from four.meme factory CREATE2 opcode
    let init_code = hex::decode(
        ""
    ).expect("valid hex");

    keccak256(&init_code)
}

/// Compute keccak256 hash of the V2 token init code
pub fn compute_init_code_hash_v2() -> B256 {
    // Token init code from four.meme V2 factory CREATE2 opcode
    let init_code = hex::decode(
        ""
    ).expect("valid hex V2");

    keccak256(&init_code)
}

/// Compute CREATE2 address
/// Formula: keccak256(0xff ++ factory ++ salt ++ init_code_hash)[12:]
pub fn compute_create2_address(factory: Address, salt: B256, init_code_hash: B256) -> Address {
    let mut data = [0u8; 85];
    data[0] = 0xff;
    data[1..21].copy_from_slice(factory.as_slice());
    data[21..53].copy_from_slice(salt.as_slice());
    data[53..85].copy_from_slice(init_code_hash.as_slice());

    let hash = keccak256(&data);
    Address::from_slice(&hash[12..])
}

